define(["jquery","core/ajax","core/notification"],function($,Ajax,Notification){return{init:function(idkey){$("#response-message-open").click(function(){$("#response-message-area").hide(300);$(".response-message").show(300)});$("#id_buttonar_resolvedbutton").removeClass("btn-primary").addClass("btn-info");$("#id_buttonar_closebutton").removeClass("btn-primary").addClass("btn-danger");$("#changue_status,#changue_priority,#changue_category").on("change",function(){var value=$(this).val();Ajax.call([{methodname:"local_helpdesk_ticket_column",args:{idkey:idkey,column:$(this).attr("data-column"),value:value}}])[0].then(function(data){$("#local_helpdesk_ticket_column").show(200).html(data.status);setTimeout(function(){$("#local_helpdesk_ticket_column").show(200)},2e3);return data}).catch(Notification.exception)})}}});
